r0_mix = model_mix.do(set={"X": 0.0}, kind="mean")
r1_mix = model_mix.do(set={"X": 1.0}, kind="mean")

ate_mix = r1_mix - r0_mix
print(f"P(Y=1 | do(X=0)): {r0_mix.mean('Y'):.3f}")
print(f"P(Y=1 | do(X=1)): {r1_mix.mean('Y'):.3f}")
print(f"ATE (risk difference): {ate_mix.mean('Y'):.3f}")
print(f"94% HDI: {ate_mix.hdi('Y', prob=0.94)}")
